+fn sqlite_value_to_rusqlite(value: &SqliteValue) -> RusqliteValue {
+    match value {
+        SqliteValue::Null => RusqliteValue::Null,
+        SqliteValue::Integer(value) => RusqliteValue::Integer(*value),
+        SqliteValue::Float(value) => RusqliteValue::Real(*value),
